    """
    Provide a vector value that can be connected to other nodes in the tree

    Outputs
    -------
    o.vector : VectorSocket
        Vector
    """

    _bl_idname = "FunctionNodeInputVector"
    node: bpy.types.FunctionNodeInputVector

    class _Inputs(SocketAccessor):
        pass

    class _Outputs(SocketAccessor):
        vector: VectorSocket
        """Vector"""

    if TYPE_CHECKING:

        @property
        def i(self) -> _Inputs: ...
        @property
        def o(self) -> _Outputs: ...

    def __init__(
        self,
        vector: tuple[float, float, float] = (0.0, 0.0, 0.0),
        vector_dimensions: int = 3,
    ):
        super().__init__()
        key_args = {}
        self.vector = vector
        self.vector_dimensions = vector_dimensions
        self._establish_links(**key_args)

    @property
    def vector(self) -> Vector:
        return self.node.vector

    @vector.setter
    def vector(self, value: Vector | tuple[float, float, float]):
        self.node.vector = value

    @property
    def vector_dimensions(self) -> int:
        return self.node.vector_dimensions

    @vector_dimensions.setter
    def vector_dimensions(self, value: int):
        self.node.vector_dimensions = value


