class VertexOfCorner(BaseNode):
    """
    Retrieve the vertex each face corner is attached to

    Parameters
    ----------
    corner_index : InputInteger
        Corner Index

    Inputs
    ------
    i.corner_index : IntegerSocket
        Corner Index

    Outputs
    -------
    o.vertex_index : IntegerSocket
        Vertex Index
    """

    _bl_idname = "GeometryNodeVertexOfCorner"
    node: bpy.types.GeometryNodeVertexOfCorner

    class _Inputs(SocketAccessor):
        corner_index: IntegerSocket
        """Corner Index"""

    class _Outputs(SocketAccessor):
        vertex_index: IntegerSocket
        """Vertex Index"""

    if TYPE_CHECKING:

        @property
        def i(self) -> _Inputs: ...
        @property
        def o(self) -> _Outputs: ...

    def __init__(self, corner_index: InputInteger = 0):
        super().__init__()
        key_args = {"Corner Index": corner_index}

        self._establish_links(**key_args)


